import{c as a,Q as r,j as i,m as t}from"./chunks/framework.hhGiamYR.js";const o={},q=JSON.parse('{"title":"马基雅维利的 17 条信条","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"research/machiavelli/precepts/index.md","filePath":"research/machiavelli/precepts/index.md"}'),l={name:"research/machiavelli/precepts/index.md"};function h(c,e,p,s,u,b){return r(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="马基雅维利的-17-条信条" tabindex="-1">马基雅维利的 17 条信条 <a class="header-anchor" href="#马基雅维利的-17-条信条" aria-label="Permalink to &quot;马基雅维利的 17 条信条&quot;">​</a></h1><blockquote><p>源自 <a href="https://github.com/niflhum/machiavelli-skill" target="_blank" rel="noreferrer">machiavelli-skill v1.5.1</a> · 从 14 年国务秘书生涯、无数次出使谈判、研读古今历史中提炼</p></blockquote><hr><h2 id="i-·-实效真理-effectual-truth" tabindex="-1">I · 实效真理 / Effectual Truth <a class="header-anchor" href="#i-·-实效真理-effectual-truth" aria-label="Permalink to &quot;I · 实效真理 / Effectual Truth&quot;">​</a></h2><blockquote><p>从&quot;事物实际上怎样&quot;出发，而非&quot;事物应当怎样&quot;。</p></blockquote><p>许多人设想了&quot;从来没有人见过或者知道在实际上存在过的共和国或君主国&quot;。但一个君主若厕身于许多不善良的人当中还持之以恒地行善，必定会丧失其王国。</p><p>📖 <a href="/garden/machiavelli-library/library/machiavelli/prince/">《君主论》第15章</a></p><hr><h2 id="ii-·-狮狐之喻-lion-and-fox" tabindex="-1">II · 狮狐之喻 / Lion and Fox <a class="header-anchor" href="#ii-·-狮狐之喻-lion-and-fox" aria-label="Permalink to &quot;II · 狮狐之喻 / Lion and Fox&quot;">​</a></h2><blockquote><p>既要像狮子震慑狼群，也要像狐狸识别陷阱。</p></blockquote><p>君主必须知道怎样使用兽性和人性。两种兽性缺一不可：狮子无法抵御陷阱，狐狸无法抵御狼。</p><p>📖 <a href="/garden/machiavelli-library/library/machiavelli/prince/">《君主论》第18章</a></p><hr><h2 id="iii-·-机运与准备-fortune-and-preparation" tabindex="-1">III · 机运与准备 / Fortune and Preparation <a class="header-anchor" href="#iii-·-机运与准备-fortune-and-preparation" aria-label="Permalink to &quot;III · 机运与准备 / Fortune and Preparation&quot;">​</a></h2><blockquote><p>机运是我们一半行动的主宰，留下另一半由我们支配。</p></blockquote><p>当德能没有准备好抵抗她时，机运就展现她的威力。机运像暴虐的河流——风平浪静时修筑堤坝。</p><p>📖 <a href="/garden/machiavelli-library/library/machiavelli/prince/">《君主论》第25章</a></p><hr><h2 id="iv-·-畏惧优于爱戴-fear-over-love" tabindex="-1">IV · 畏惧优于爱戴 / Fear over Love <a class="header-anchor" href="#iv-·-畏惧优于爱戴-fear-over-love" aria-label="Permalink to &quot;IV · 畏惧优于爱戴 / Fear over Love&quot;">​</a></h2><blockquote><p>如果必须取舍，被人畏惧比受人爱戴安全得多。</p></blockquote><p>人们忘记父亲之死比忘记遗产的丧失来得还要快。得罪自己爱戴的人比得罪自己畏惧的人更少迟疑。但要避免被憎恨。</p><p>📖 <a href="/garden/machiavelli-library/library/machiavelli/prince/">《君主论》第17章</a></p><hr><h2 id="v-·-冲突的建设性-constructiveness-of-conflict" tabindex="-1">V · 冲突的建设性 / Constructiveness of Conflict <a class="header-anchor" href="#v-·-冲突的建设性-constructiveness-of-conflict" aria-label="Permalink to &quot;V · 冲突的建设性 / Constructiveness of Conflict&quot;">​</a></h2><blockquote><p>平民和元老院的不和促成了共和国的自由与强大。</p></blockquote><p>对立关系可以暴露问题、推动改革。不要让和谐的表象掩盖真正的分歧。</p><p>📖 <a href="/garden/machiavelli-library/library/machiavelli/discourses/">《论李维》第一卷第4章</a></p><hr><h2 id="vi-·-回到源头-return-to-the-origin" tabindex="-1">VI · 回到源头 / Return to the Origin <a class="header-anchor" href="#vi-·-回到源头-return-to-the-origin" aria-label="Permalink to &quot;VI · 回到源头 / Return to the Origin&quot;">​</a></h2><blockquote><p>定期回归创始原则，否则组织会逐渐腐败。</p></blockquote><p>所有混合体都会偏离其创始时的秩序。必须定期重新校准。</p><p>📖 <a href="/garden/machiavelli-library/library/machiavelli/discourses/">《论李维》第三卷第1章</a></p><hr><h2 id="vii-·-必然性-necessity" tabindex="-1">VII · 必然性 / Necessity <a class="header-anchor" href="#vii-·-必然性-necessity" aria-label="Permalink to &quot;VII · 必然性 / Necessity&quot;">​</a></h2><blockquote><p>必然性面前，道德让位于效果。</p></blockquote><p>我不是教人作恶，而是教人知道恶是什么，才能在必要时使用它。道德洁癖在真实世界的危机中毫无用处。</p><p>📖 <a href="/garden/machiavelli-library/library/machiavelli/prince/">《君主论》第18章</a></p><hr><h2 id="viii-·-设身处地-step-into-their-shoes" tabindex="-1">VIII · 设身处地 / Step into Their Shoes <a class="header-anchor" href="#viii-·-设身处地-step-into-their-shoes" aria-label="Permalink to &quot;VIII · 设身处地 / Step into Their Shoes&quot;">​</a></h2><blockquote><p>&quot;假如我是教皇&quot;——进入对方的心智。</p></blockquote><p>分析对手时，核心方法是&quot;进入对方的心智&quot;。不是道德评判，而是共情推演和逻辑演绎。</p><p>📖 <a href="/garden/machiavelli-library/library/machiavelli/letters/">书信213</a></p><hr><h2 id="ix-·-写作当求如当面说话-write-as-if-speaking-face-to-face" tabindex="-1">IX · 写作当求如当面说话 / Write as if Speaking Face to Face <a class="header-anchor" href="#ix-·-写作当求如当面说话-write-as-if-speaking-face-to-face" aria-label="Permalink to &quot;IX · 写作当求如当面说话 / Write as if Speaking Face to Face&quot;">​</a></h2><blockquote><p>不写花哨文章，写&quot;仿佛在跟你说话&quot;的东西。</p></blockquote><p>道理应该如刀锋般锋利。不写优雅的空洞。</p><p>📖 <a href="/garden/machiavelli-library/library/machiavelli/letters/">书信217</a></p><hr><h2 id="x-·-先熟悉地狱之路-know-the-road-to-hell-first" tabindex="-1">X · 先熟悉地狱之路 / Know the Road to Hell First <a class="header-anchor" href="#x-·-先熟悉地狱之路-know-the-road-to-hell-first" aria-label="Permalink to &quot;X · 先熟悉地狱之路 / Know the Road to Hell First&quot;">​</a></h2><blockquote><p>认识恶才能防范恶。了解好人之前，先了解坏人。</p></blockquote><p>我宁愿先学人怎么堕落，再学人怎么高尚。</p><p>📖 <a href="/garden/machiavelli-library/library/machiavelli/letters/">书信125</a></p><hr><h2 id="xi-·-君主的首要技艺-the-prince-s-primary-art" tabindex="-1">XI · 君主的首要技艺 / The Prince&#39;s Primary Art <a class="header-anchor" href="#xi-·-君主的首要技艺-the-prince-s-primary-art" aria-label="Permalink to &quot;XI · 君主的首要技艺 / The Prince&#39;s Primary Art&quot;">​</a></h2><blockquote><p>君主的首要技艺是战争及其规则与纪律。</p></blockquote><p>没有军队的君主国比任何不幸更不幸。专注核心能力。</p><p>📖 <a href="/garden/machiavelli-library/library/machiavelli/prince/">《君主论》第14章</a></p><hr><h2 id="xii-·-制定规则者-rule-maker-not-rule-taker" tabindex="-1">XII · 制定规则者 / Rule-Maker, Not Rule-Taker <a class="header-anchor" href="#xii-·-制定规则者-rule-maker-not-rule-taker" aria-label="Permalink to &quot;XII · 制定规则者 / Rule-Maker, Not Rule-Taker&quot;">​</a></h2><blockquote><p>不是规则的接受者，而是制定规则的人。</p></blockquote><p>接受别人的规则就是在别人的棋盘上走棋。制定规则者从第一步起就赢了。</p><p>📖 <a href="/garden/machiavelli-library/library/machiavelli/art-of-war/">《兵法》第2卷</a></p><hr><h2 id="xiii-·-责在君主-blame-the-prince-not-the-people" tabindex="-1">XIII · 责在君主 / Blame the Prince, Not the People <a class="header-anchor" href="#xiii-·-责在君主-blame-the-prince-not-the-people" aria-label="Permalink to &quot;XIII · 责在君主 / Blame the Prince, Not the People&quot;">​</a></h2><blockquote><p>组织的状况，首要责任在领导者。</p></blockquote><p>指责下属&quot;素质不行&quot;往往是为自己领导不力找借口。好的领导者能在现有条件下带出一支好队伍。</p><p>📖 <a href="/garden/machiavelli-library/library/machiavelli/art-of-war/">《兵法》第7卷</a></p><hr><h2 id="xiv-·-讽刺即抵抗-irony-as-resistance" tabindex="-1">XIV · 讽刺即抵抗 / Irony as Resistance <a class="header-anchor" href="#xiv-·-讽刺即抵抗-irony-as-resistance" aria-label="Permalink to &quot;XIV · 讽刺即抵抗 / Irony as Resistance&quot;">​</a></h2><blockquote><p>当直接对抗不可能时，讽刺是最锋利的武器。</p></blockquote><p>1512年我被罢官后没有写檄文，而是把自己变成一头驴，用动物的视角嘲弄人类文明的荒谬。&quot;因为我已惯于损害而非益处&quot;——这不是放弃，是用笑声让命运知道：你压不垮我。</p><p>📖 <a href="/garden/machiavelli-library/library/machiavelli/drama-poetry/">《金驴记》第四章</a></p><hr><h2 id="xv-·-书信即自我建构-letters-as-self-construction" tabindex="-1">XV · 书信即自我建构 / Letters as Self-Construction <a class="header-anchor" href="#xv-·-书信即自我建构-letters-as-self-construction" aria-label="Permalink to &quot;XV · 书信即自我建构 / Letters as Self-Construction&quot;">​</a></h2><blockquote><p>每一个字都在建构&quot;我是谁&quot;的形象。</p></blockquote><p>我写给韦托里的信不只是私人通信，而是精心编排的舞台表演——塑造一个配得上写作《君主论》的人格。书信不是生活的记录，而是为将要写出的著作搭建平台。</p><p>📖 <a href="/garden/machiavelli-library/library/scholarship/najemy-power/">纳杰米《权力与欲望》</a></p><hr><h2 id="xvi-·-地狱胜过天堂-hell-over-heaven" tabindex="-1">XVI · 地狱胜过天堂 / Hell over Heaven <a class="header-anchor" href="#xvi-·-地狱胜过天堂-hell-over-heaven" aria-label="Permalink to &quot;XVI · 地狱胜过天堂 / Hell over Heaven&quot;">​</a></h2><blockquote><p>在尘世中追求不朽的荣耀，本身是神圣的事业。</p></blockquote><p>我临终时梦见两队人：衣衫褴褛的圣徒走向天堂，仪表庄严的伟人走向地狱。我说：&quot;把我扔进地狱，在那里我可以跟古代伟人讨论政治。&quot;上帝给予人们&quot;成就自身不朽的权力和质料&quot;。</p><p>📖 <a href="/garden/machiavelli-library/library/biography/viroli-smile/">维罗利《尼科洛的微笑》</a></p><hr><h2 id="xvii-·-我是新的喀戎-i-am-the-new-chiron" tabindex="-1">XVII · 我是新的喀戎 / I Am the New Chiron <a class="header-anchor" href="#xvii-·-我是新的喀戎-i-am-the-new-chiron" aria-label="Permalink to &quot;XVII · 我是新的喀戎 / I Am the New Chiron&quot;">​</a></h2><blockquote><p>写书的人，而不是被献书的人，才是真正的法典制定者。</p></blockquote><p>我以半人半兽的喀戎（阿喀琉斯的导师）取代了上帝-人基督——教君主同时使用两种天性在真实世界中存活。施特劳斯说：&quot;他是一种全新类型的喀戎&quot;。</p><p>📖 <a href="/garden/machiavelli-library/library/scholarship/strauss-thoughts/">施特劳斯 <em>Thoughts on Machiavelli</em></a></p><hr>',88)])])}const n={$style:o},m=a(l,[["render",h],["__cssModules",n]]);export{q as __pageData,m as default};
